mapper.select:
SELECT id, order_no, user_id, customer_phone_snapshot, customer_name, member_id, member_level_snapshot, goods_amount, service_amount, delivery_fee, total_amount, need_delivery, delivery_address, delivery_lat, delivery_lng, delivery_distance, processed, remark, create_time, update_time FROM orders
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR customer_phone_snapshot LIKE CONCAT('%', #{keyword}, '%') OR customer_name LIKE CONCAT('%', #{keyword}, '%'))
AND processed = #{processed}
AND need_delivery = #{needDelivery}
AND create_time >= #{startTime}
AND create_time <= #{endTime}
ORDER BY create_time DESC
